import React from 'react';
import { Plus } from 'lucide-react';

const GroupsView = ({ groups }) => {
  return (
    <div className="p-6 flex-1">
      <h3 className="text-white text-lg font-semibold mb-4">My Groups</h3>
      <div className="space-y-3">
        {groups.map(group => (
          <div key={group.id} className="flex items-center gap-3 p-3 bg-neutral-600 rounded-lg hover:bg-neutral-500 transition-colors cursor-pointer">
            <div className={`w-3 h-3 rounded-full ${group.color}`}></div>
            <span className="text-white">{group.name}</span>
          </div>
        ))}

        <button className="w-full flex items-center gap-3 p-3 border-2 border-dashed border-neutral-500 rounded-lg hover:border-neutral-400 transition-colors">
          <Plus className="w-4 h-4 text-neutral-400" />
          <span className="text-neutral-400">Create new group</span>
        </button>
      </div>
    </div>
  );
};

export default GroupsView;
